mapper.select:
select *
from check_in_record
where user_id = #{userId}
  and check_in_date = #{checkInDate}
limit 1

select *
from check_in_fail_record
where user_id = #{userId}
  and check_in_date = #{checkInDate}
limit 1

select count(1)
from check_in_record
where user_id = #{userId}

mapper.update:
update check_in_summary
set consecutive_days = #{consecutiveDays},
    total_days = #{totalDays},
    last_success_date = #{lastSuccessDate}
where user_id = #{userId}

mapper.delete:
delete from check_in_fail_record
where user_id = #{userId}
  and check_in_date = #{checkInDate}
